// Naive recursive — O(2^n) time, each call branches twice
function fibNaive(n) {
  if (n <= 1) return n;
  return fibNaive(n - 1) + fibNaive(n - 2); // exponential call tree
}

// Memoised — O(n) time, O(n) space; each subproblem computed once
function fibMemo(n, memo = new Map()) {
  if (n <= 1) return n;
  if (memo.has(n)) return memo.get(n);   // O(1) lookup
  const result = fibMemo(n - 1, memo) + fibMemo(n - 2, memo);
  memo.set(n, result);                    // O(1) store
  return result;
}

// Iterative — O(n) time, O(1) space; no recursion overhead
function fibIter(n) {
  if (n <= 1) return n;
  let [a, b] = [0, 1];
  for (let i = 2; i <= n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}

console.log(fibMemo(40)); // 102334155 — instant
// fibNaive(40) takes ~several seconds due to ~2^40 calls
console.log(fibIter(40)); // 102334155 — O(1) space

# line_profiler — per-line timing (pip install line-profiler)
# Decorate target function and run: kernprof -l -v script.py

@profile   # injected by kernprof
def assemble_context(messages, docs):
    tokens = []
    for msg in messages:          # <-- line-level timing shows if this is hot
        tokens.append(tokenise(msg))
    for doc in docs:
        tokens.append(tokenise(doc))
    return truncate(tokens, 128_000)
